You're welcome! To add filtering functionality, we can introduce a `--filter` flag for the `summarize` command. We'll modify the command to check if the specified tag exists in the `Tags` field of the YAML content before printing the summary. Here's how you can enhance your `cmd/summarize.go` file:

```go
package cmd

import (
	"fmt"
	"io/ioutil"
	"log"
	"strings"

	"github.com/spf13/cobra"
	"gopkg.in/yaml.v2"
)

type Config struct {
	Name string   `yaml:"name"`
	Age  int      `yaml:"age"`
	Tags []string `yaml:"tags"`
}

var filterTag string

// summarizeCmd represents the summarize command
var summarizeCmd = &cobra.Command{
	Use:   "summarize [file]",
	Short: "Summarize the contents of a YAML configuration file",
	Args:  cobra.ExactArgs(1),
	Run: func(cmd *cobra.Command, args []string) {
		filePath := args[0]
		summary, err := processYAML(filePath, filterTag)
		if err != nil {
			log.Fatalf("Error processing YAML: %v", err)
		}
		if summary != "" {
			fmt.Println(summary)
		} else {
			fmt.Println("No data matched the filter.")
		}
	},
}

func processYAML(filePath string, filter string) (string, error) {
	data, err := ioutil.ReadFile(filePath)
	if err != nil {
		return "", fmt.Errorf("unable to read file: %v", err)
	}

	var config Config
	if err := yaml.Unmarshal(data, &config); err != nil {
		return "", fmt.Errorf("unable to parse YAML: %v", err)
	}

	if filter != "" {
		for _, tag := range config.Tags {
			if strings.EqualFold(tag, filter) {
				return fmt.Sprintf("Name: %s\nAge: %d\nTags: %v", config.Name, config.Age, config.Tags), nil
			}
		}
		return "", nil // No matching tag found
	}

	return fmt.Sprintf("Name: %s\nAge: %d\nTags: %v", config.Name, config.Age, config.Tags), nil
}

func init() {
	// Add the --filter flag to the command
	summarizeCmd.Flags().StringVarP(&filterTag, "filter", "f", "", "Filter results by a specific tag")
	rootCmd.AddCommand(summarizeCmd)
}
```

Here’s what changed:

1. **Added a `--filter` flag**:
   - In the `init()` function, I added a `filter` flag using `StringVarP`. It assigns any value passed via `--filter` (or `-f`) to the `filterTag` variable.

2. **Modified the `processYAML()` function**:
   - Added a `filter` parameter to this function.
   - If a filter is provided, the function checks if the `filter` value exists in the `Tags` field of the YAML.
   - If the filter matches a tag, the function returns the summary. Otherwise, it returns an empty string.

3. **Updated the main logic**:
   - The `Run` function for the `summarize` command now handles the case where no data matches the filter and displays a message accordingly.

### Usage Example
Given the same `config.yaml` file:
```yaml
name: John Doe
age: 30
tags:
  - developer
  - gopher
```

You can run the following:
```bash
# Without a filter (shows full summary)
go run main.go summarize config.yaml

# With a filter that matches
go run main.go summarize config.yaml --filter gopher

# With a filter that doesn't match
go run main.go summarize config.yaml --filter python
```

### Outputs
1. Without a filter:
```
Name: John Doe
Age: 30
Tags: [developer gopher]
```

2. With the filter `--filter gopher`:
```
Name: John Doe
Age: 30
Tags: [developer gopher]
```

3. With the filter `--filter python`:
```
No data matched the filter.
```

This enhancement allows users to extract targeted information based on the tags they’re interested in. Let me know if you’d like to add further features, such as case-insensitive filtering or advanced query logic!

Absolutely, we can add a `--json` flag to control the output format. When the flag is set, we’ll convert the filtered result to JSON and print it rather than plain text. Here’s how we can modify `cmd/summarize.go` to include this functionality:

### Updated Code

```go
package cmd

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"log"
	"strings"

	"github.com/spf13/cobra"
	"gopkg.in/yaml.v2"
)

type Config struct {
	Name string   `yaml:"name"`
	Age  int      `yaml:"age"`
	Tags []string `yaml:"tags"`
}

var (
	filterTag string
	outputJSON bool
)

// summarizeCmd represents the summarize command
var summarizeCmd = &cobra.Command{
	Use:   "summarize [file]",
	Short: "Summarize the contents of a YAML configuration file",
	Args:  cobra.ExactArgs(1),
	Run: func(cmd *cobra.Command, args []string) {
		filePath := args[0]
		config, err := parseYAML(filePath)
		if err != nil {
			log.Fatalf("Error processing YAML: %v", err)
		}

		// Filter the results if a filter tag is provided
		if filterTag != "" {
			config = filterConfigByTag(config, filterTag)
			if config == nil {
				fmt.Println("No data matched the filter.")
				return
			}
		}

		// Output as JSON or plain text
		if outputJSON {
			err = printJSON(config)
			if err != nil {
				log.Fatalf("Error converting to JSON: %v", err)
			}
		} else {
			printSummary(config)
		}
	},
}

func parseYAML(filePath string) (*Config, error) {
	data, err := ioutil.ReadFile(filePath)
	if err != nil {
		return nil, fmt.Errorf("unable to read file: %v", err)
	}

	var config Config
	if err := yaml.Unmarshal(data, &config); err != nil {
		return nil, fmt.Errorf("unable to parse YAML: %v", err)
	}

	return &config, nil
}

func filterConfigByTag(config *Config, filter string) *Config {
	for _, tag := range config.Tags {
		if strings.EqualFold(tag, filter) {
			return config
		}
	}
	return nil // No matching tag found
}

func printSummary(config *Config) {
	fmt.Printf("Name: %s\nAge: %d\nTags: %v\n", config.Name, config.Age, config.Tags)
}

func printJSON(config *Config) error {
	jsonData, err := json.MarshalIndent(config, "", "  ")
	if err != nil {
		return err
	}
	fmt.Println(string(jsonData))
	return nil
}

func init() {
	// Add flags for filtering and JSON output
	summarizeCmd.Flags().StringVarP(&filterTag, "filter", "f", "", "Filter results by a specific tag")
	summarizeCmd.Flags().BoolVarP(&outputJSON, "json", "j", false, "Output the result as JSON")
	rootCmd.AddCommand(summarizeCmd)
}
```

### Key Changes
1. **Added a `--json` flag**:
   - Declared a `outputJSON` variable to hold the flag value.
   - Registered the flag in the `init()` function with `summarizeCmd.Flags().BoolVarP`.

2. **Separated Parsing and Filtering**:
   - Created a `parseYAML()` function to handle YAML file reading and parsing.
   - Created a `filterConfigByTag()` function to filter the parsed data if a tag is specified.

3. **Output as JSON**:
   - Created a `printJSON()` function that takes the `Config` struct, converts it to JSON with `json.MarshalIndent`, and prints the output.
   - Modified the `Run` function to choose between plain text and JSON output based on the `--json` flag.

4. **Improved Error Handling**:
   - Added error checks for the JSON conversion and file parsing for better user feedback.

### Usage Example
Given the same `config.yaml` file:
```yaml
name: John Doe
age: 30
tags:
  - developer
  - gopher
```

#### Commands and Outputs
1. **Plain Text Output Without Filter**:
```bash
go run main.go summarize config.yaml
```
Output:
```
Name: John Doe
Age: 30
Tags: [developer gopher]
```

2. **Plain Text Output With Filter**:
```bash
go run main.go summarize config.yaml --filter gopher
```
Output:
```
Name: John Doe
Age: 30
Tags: [developer gopher]
```

3. **JSON Output Without Filter**:
```bash
go run main.go summarize config.yaml --json
```
Output:
```json
{
  "Name": "John Doe",
  "Age": 30,
  "Tags": [
    "developer",
    "gopher"
  ]
}
```

4. **JSON Output With Filter**:
```bash
go run main.go summarize config.yaml --filter gopher --json
```
Output:
```json
{
  "Name": "John Doe",
  "Age": 30,
  "Tags": [
    "developer",
    "gopher"
  ]
}
```

5. **No Matching Filter**:
```bash
go run main.go summarize config.yaml --filter python --json
```
Output:
```
No data matched the filter.
```

This feature makes your tool much more versatile by allowing users to choose structured JSON output, especially useful for machine-readable results. Let me know if you’d like more enhancements or explanations!

No problem, I'll help you implement a complete health check service. This service will run as an independent component and periodically check the health status of all microservices.

First is `config.go`, which is responsible for loading the YAML configuration:```go
// internal/healthcheck/config.go
package healthcheck

import (
	"fmt"
	"os"
	"time"

	"gopkg.in/yaml.v3"
)

// Config represents the top-level configuration
type Config struct {
	Server  ServerConfig  `yaml:"server"`
	Targets []Target      `yaml:"targets"`
	Report  ReportConfig  `yaml:"report"`
}

// ServerConfig holds HTTP server settings
type ServerConfig struct {
	Port         int           `yaml:"port"`
	ReadTimeout  time.Duration `yaml:"read_timeout"`
	WriteTimeout time.Duration `yaml:"write_timeout"`
}

// Target represents a single health check target
type Target struct {
	Name     string        `yaml:"name"`
	Type     CheckType     `yaml:"type"` // http, tcp, grpc
	Endpoint string        `yaml:"endpoint"`
	Interval time.Duration `yaml:"interval"`
	Timeout  time.Duration `yaml:"timeout"`
	Retries  int           `yaml:"retries"`
	Headers  map[string]string `yaml:"headers,omitempty"`
	// HTTP-specific
	ExpectedStatus int    `yaml:"expected_status,omitempty"`
	ExpectedBody   string `yaml:"expected_body,omitempty"`
	// gRPC-specific
	GRPCService string `yaml:"grpc_service,omitempty"`
	UseTLS      bool   `yaml:"use_tls,omitempty"`
}

// ReportConfig holds reporting settings
type ReportConfig struct {
	AggregationInterval time.Duration `yaml:"aggregation_interval"`
	RetentionPeriod     time.Duration `yaml:"retention_period"`
	WebhookURL          string        `yaml:"webhook_url,omitempty"`
	SlackChannel        string        `yaml:"slack_channel,omitempty"`
}

// CheckType represents the protocol type
type CheckType string

const (
	CheckTypeHTTP CheckType = "http"
	CheckTypeTCP  CheckType = "tcp"
	CheckTypeGRPC CheckType = "grpc"
)

// LoadConfig reads and parses the YAML config file
func LoadConfig(path string) (*Config, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("failed to read config file %s: %w", path, err)
	}

	// Expand environment variables
	expanded := os.ExpandEnv(string(data))

	var cfg Config
	if err := yaml.Unmarshal([]byte(expanded), &cfg); err != nil {
		return nil, fmt.Errorf("failed to parse config: %w", err)
	}

	if err := cfg.Validate(); err != nil {
		return nil, fmt.Errorf("config validation failed: %w", err)
	}

	return &cfg, nil
}

// Validate checks the config for logical errors
func (c *Config) Validate() error {
	if c.Server.Port <= 0 || c.Server.Port > 65535 {
		return fmt.Errorf("invalid server port: %d", c.Server.Port)
	}
	if len(c.Targets) == 0 {
		return fmt.Errorf("at least one target is required")
	}
	for i, t := range c.Targets {
		if t.Name == "" {
			return fmt.Errorf("target[%d]: name is required", i)
		}
		if t.Endpoint == "" {
			return fmt.Errorf("target[%d] (%s): endpoint is required", i, t.Name)
		}
		switch t.Type {
		case CheckTypeHTTP, CheckTypeTCP, CheckTypeGRPC:
			// valid
		default:
			return fmt.Errorf("target[%d] (%s): invalid type %q (must be http, tcp, or grpc)", i, t.Name, t.Type)
		}
		if t.Interval <= 0 {
			return fmt.Errorf("target[%d] (%s): interval must be positive", i, t.Name)
		}
		if t.Timeout <= 0 {
			return fmt.Errorf("target[%d] (%s): timeout must be positive", i, t.Name)
		}
		if t.Timeout >= t.Interval {
			return fmt.Errorf("target[%d] (%s): timeout must be less than interval", i, t.Name)
		}
	}
	return nil
}
```Next is the core `checker.go`, which implements health checks for three protocols:```go
// internal/healthcheck/checker.go
package healthcheck

import (
	"context"
	"crypto/tls"
	"fmt"
	"io"
	"net"
	"net/http"
	"strings"
	"sync"
	"time"

	"google.golang.org/grpc"
	"google.golang.org/grpc/credentials"
	"google.golang.org/grpc/credentials/insecure"
	healthpb "google.golang.org/grpc/health/grpc_health_v1"
)

// CheckResult holds the result of a single health check
type CheckResult struct {
	TargetName string        `json:"target_name"`
	Type       CheckType     `json:"type"`
	Status     HealthStatus  `json:"status"`
	Latency    time.Duration `json:"latency_ms"`
	Message    string        `json:"message,omitempty"`
	Timestamp  time.Time     `json:"timestamp"`
	RetryCount int           `json:"retry_count"`
}

// HealthStatus represents the health state
type HealthStatus string

const (
	StatusHealthy   HealthStatus = "healthy"
	StatusUnhealthy HealthStatus = "unhealthy"
	StatusDegraded  HealthStatus = "degraded"
	StatusUnknown   HealthStatus = "unknown"
)

// Checker manages health checks for all targets
type Checker struct {
	config     *Config
	results    map[string]*CheckResult
	mu         sync.RWMutex
	httpClient *http.Client
	stopCh     chan struct{}
	wg         sync.WaitGroup
	callbacks  []func(CheckResult)
}

// NewChecker creates a new health checker
func NewChecker(cfg *Config) *Checker {
	return &Checker{
		config:  cfg,
		results: make(map[string]*CheckResult),
		httpClient: &http.Client{
			Timeout: 30 * time.Second,
			Transport: &http.Transport{
				MaxIdleConns:        100,
				MaxIdleConnsPerHost: 10,
				IdleConnTimeout:     90 * time.Second,
				TLSClientConfig:    &tls.Config{MinVersion: tls.VersionTLS12},
			},
		},
		stopCh: make(chan struct{}),
	}
}

// OnResult registers a callback for check results
func (c *Checker) OnResult(fn func(CheckResult)) {
	c.callbacks = append(c.callbacks, fn)
}

// Start begins periodic health checking for all targets
func (c *Checker) Start() {
	for _, target := range c.config.Targets {
		c.wg.Add(1)
		go c.runChecks(target)
	}
}

// Stop gracefully shuts down the checker
func (c *Checker) Stop() {
	close(c.stopCh)
	c.wg.Wait()
}

// GetResult returns the latest result for a target
func (c *Checker) GetResult(name string) (*CheckResult, bool) {
	c.mu.RLock()
	defer c.mu.RUnlock()
	r, ok := c.results[name]
	return r, ok
}

// GetAllResults returns all current results
func (c *Checker) GetAllResults() map[string]*CheckResult {
	c.mu.RLock()
	defer c.mu.RUnlock()
	copy := make(map[string]*CheckResult, len(c.results))
	for k, v := range c.results {
		copy[k] = v
	}
	return copy
}

func (c *Checker) runChecks(target Target) {
	defer c.wg.Done()
	ticker := time.NewTicker(target.Interval)
	defer ticker.Stop()

	// Run an initial check immediately
	c.executeCheck(target)

	for {
		select {
		case <-ticker.C:
			c.executeCheck(target)
		case <-c.stopCh:
			return
		}
	}
}

func (c *Checker) executeCheck(target Target) {
	var result CheckResult
	result.TargetName = target.Name
	result.Type = target.Type
	result.Timestamp = time.Now()

	var err error
	var latency time.Duration

	for attempt := 0; attempt <= target.Retries; attempt++ {
		result.RetryCount = attempt
		start := time.Now()

		switch target.Type {
		case CheckTypeHTTP:
			err = c.checkHTTP(target)
		case CheckTypeTCP:
			err = c.checkTCP(target)
		case CheckTypeGRPC:
			err = c.checkGRPC(target)
		default:
			err = fmt.Errorf("unsupported check type: %s", target.Type)
		}

		latency = time.Since(start)

		if err == nil {
			break
		}

		if attempt < target.Retries {
			time.Sleep(time.Second * time.Duration(attempt+1))
		}
	}

	result.Latency = latency
	if err != nil {
		result.Status = StatusUnhealthy
		result.Message = err.Error()
	} else if latency > target.Timeout/2 {
		result.Status = StatusDegraded
		result.Message = fmt.Sprintf("high latency: %v", latency)
	} else {
		result.Status = StatusHealthy
	}

	c.mu.Lock()
	c.results[target.Name] = &result
	c.mu.Unlock()

	for _, cb := range c.callbacks {
		cb(result)
	}
}

func (c *Checker) checkHTTP(target Target) error {
	ctx, cancel := context.WithTimeout(context.Background(), target.Timeout)
	defer cancel()

	req, err := http.NewRequestWithContext(ctx, http.MethodGet, target.Endpoint, nil)
	if err != nil {
		return fmt.Errorf("failed to create request: %w", err)
	}

	req.Header.Set("User-Agent", "healthcheck-service/1.0")
	for k, v := range target.Headers {
		req.Header.Set(k, v)
	}

	resp, err := c.httpClient.Do(req)
	if err != nil {
		return fmt.Errorf("HTTP request failed: %w", err)
	}
	defer resp.Body.Close()

	expectedStatus := target.ExpectedStatus
	if expectedStatus == 0 {
		expectedStatus = http.StatusOK
	}
	if resp.StatusCode != expectedStatus {
		return fmt.Errorf("unexpected status code: got %d, want %d", resp.StatusCode, expectedStatus)
	}

	if target.ExpectedBody != "" {
		body, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024))
		if err != nil {
			return fmt.Errorf("failed to read response body: %w", err)
		}
		if !strings.Contains(string(body), target.ExpectedBody) {
			return fmt.Errorf("response body does not contain expected string %q", target.ExpectedBody)
		}
	}

	return nil
}

func (c *Checker) checkTCP(target Target) error {
	conn, err := net.DialTimeout("tcp", target.Endpoint, target.Timeout)
	if err != nil {
		return fmt.Errorf("TCP connection failed: %w", err)
	}
	defer conn.Close()
	return nil
}

func (c *Checker) checkGRPC(target Target) error {
	ctx, cancel := context.WithTimeout(context.Background(), target.Timeout)
	defer cancel()

	var opts []grpc.DialOption
	if target.UseTLS {
		opts = append(opts, grpc.WithTransportCredentials(credentials.NewTLS(&tls.Config{
			MinVersion: tls.VersionTLS12,
		})))
	} else {
		opts = append(opts, grpc.WithTransportCredentials(insecure.NewCredentials()))
	}

	conn, err := grpc.DialContext(ctx, target.Endpoint, opts...)
	if err != nil {
		return fmt.Errorf("gRPC dial failed: %w", err)
	}
	defer conn.Close()

	client := healthpb.NewHealthClient(conn)
	req := &healthpb.HealthCheckRequest{
		Service: target.GRPCService,
	}

	resp, err := client.Check(ctx, req)
	if err != nil {
		return fmt.Errorf("gRPC health check failed: %w", err)
	}

	if resp.Status != healthpb.HealthCheckResponse_SERVING {
		return fmt.Errorf("service not serving: status=%v", resp.Status)
	}

	return nil
}
```Next is `reporter.go`, which is responsible for status aggregation and report generation:```go
// internal/healthcheck/reporter.go
package healthcheck

import (
	"bytes"
	"encoding/json"
	"fmt"
	"net/http"
	"sort"
	"sync"
	"time"
)

// HealthReport represents an aggregated health report
type HealthReport struct {
	Timestamp     time.Time              `json:"timestamp"`
	OverallStatus HealthStatus           `json:"overall_status"`
	TotalTargets  int                    `json:"total_targets"`
	HealthyCount  int                    `json:"healthy_count"`
	UnhealthyCount int                   `json:"unhealthy_count"`
	DegradedCount int                    `json:"degraded_count"`
	Services      []ServiceStatus        `json:"services"`
	Uptime        map[string]float64     `json:"uptime_percentages"`
}

// ServiceStatus represents one service's status in a report
type ServiceStatus struct {
	Name       string       `json:"name"`
	Status     HealthStatus `json:"status"`
	Latency    string       `json:"latency"`
	LastCheck  time.Time    `json:"last_check"`
	Message    string       `json:"message,omitempty"`
	RetryCount int          `json:"retry_count"`
}

// HistoryEntry stores a historical check result
type HistoryEntry struct {
	Timestamp time.Time
	Status    HealthStatus
	Latency   time.Duration
}

// Reporter aggregates health check results and generates reports
type Reporter struct {
	checker   *Checker
	config    *Config
	history   map[string][]HistoryEntry
	mu        sync.RWMutex
	stopCh    chan struct{}
}

// NewReporter creates a new reporter
func NewReporter(checker *Checker, cfg *Config) *Reporter {
	r := &Reporter{
		checker: checker,
		config:  cfg,
		history: make(map[string][]HistoryEntry),
		stopCh:  make(chan struct{}),
	}

	// Register callback to record history
	checker.OnResult(func(result CheckResult) {
		r.mu.Lock()
		defer r.mu.Unlock()
		r.history[result.TargetName] = append(r.history[result.TargetName], HistoryEntry{
			Timestamp: result.Timestamp,
			Status:    result.Status,
			Latency:   result.Latency,
		})
		// Trim old entries beyond retention period
		r.trimHistory(result.TargetName)
	})

	return r
}

// Start begins periodic report generation
func (r *Reporter) Start() {
	go r.runPeriodicReports()
}

// Stop shuts down the reporter
func (r *Reporter) Stop() {
	close(r.stopCh)
}

func (r *Reporter) runPeriodicReports() {
	interval := r.config.Report.AggregationInterval
	if interval <= 0 {
		interval = 1 * time.Minute
	}
	ticker := time.NewTicker(interval)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			report := r.GenerateReport()
			if r.config.Report.WebhookURL != "" {
				r.sendWebhook(report)
			}
		case <-r.stopCh:
			return
		}
	}
}

// GenerateReport creates a full health report
func (r *Reporter) GenerateReport() *HealthReport {
	results := r.checker.GetAllResults()

	report := &HealthReport{
		Timestamp:    time.Now(),
		TotalTargets: len(r.config.Targets),
		Uptime:       make(map[string]float64),
	}

	services := make([]ServiceStatus, 0, len(results))
	for name, result := range results {
		svc := ServiceStatus{
			Name:       name,
			Status:     result.Status,
			Latency:    result.Latency.String(),
			LastCheck:  result.Timestamp,
			Message:    result.Message,
			RetryCount: result.RetryCount,
		}
		services = append(services, svc)

		switch result.Status {
		case StatusHealthy:
			report.HealthyCount++
		case StatusUnhealthy:
			report.UnhealthyCount++
		case StatusDegraded:
			report.DegradedCount++
		}

		// Calculate uptime
		report.Uptime[name] = r.calculateUptime(name)
	}

	// Sort services by name for consistent output
	sort.Slice(services, func(i, j int) bool {
		return services[i].Name < services[j].Name
	})
	report.Services = services

	// Determine overall status
	if report.UnhealthyCount > 0 {
		report.OverallStatus = StatusUnhealthy
	} else if report.DegradedCount > 0 {
		report.OverallStatus = StatusDegraded
	} else if report.HealthyCount == report.TotalTargets {
		report.OverallStatus = StatusHealthy
	} else {
		report.OverallStatus = StatusUnknown
	}

	return report
}

// calculateUptime returns uptime percentage for a target
func (r *Reporter) calculateUptime(name string) float64 {
	r.mu.RLock()
	defer r.mu.RUnlock()

	entries := r.history[name]
	if len(entries) == 0 {
		return 0.0
	}

	healthyCount := 0
	for _, e := range entries {
		if e.Status == StatusHealthy || e.Status == StatusDegraded {
			healthyCount++
		}
	}

	return float64(healthyCount) / float64(len(entries)) * 100.0
}

func (r *Reporter) trimHistory(name string) {
	retention := r.config.Report.RetentionPeriod
	if retention <= 0 {
		retention = 24 * time.Hour
	}
	cutoff := time.Now().Add(-retention)

	entries := r.history[name]
	idx := 0
	for idx < len(entries) && entries[idx].Timestamp.Before(cutoff) {
		idx++
	}
	if idx > 0 {
		r.history[name] = entries[idx:]
	}
}

func (r *Reporter) sendWebhook(report *HealthReport) error {
	payload, err := json.Marshal(report)
	if err != nil {
		return fmt.Errorf("failed to marshal report: %w", err)
	}

	resp, err := http.Post(r.config.Report.WebhookURL, "application/json", bytes.NewReader(payload))
	if err != nil {
		return fmt.Errorf("webhook request failed: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode >= 300 {
		return fmt.Errorf("webhook returned status %d", resp.StatusCode)
	}

	return nil
}

// ServeHTTP provides an HTTP handler for the report endpoint
func (r *Reporter) ServeHTTP(w http.ResponseWriter, req *http.Request) {
	report := r.GenerateReport()

	w.Header().Set("Content-Type", "application/json")

	if report.OverallStatus == StatusUnhealthy {
		w.WriteHeader(http.StatusServiceUnavailable)
	} else {
		w.WriteHeader(http.StatusOK)
	}

	encoder := json.NewEncoder(w)
	encoder.SetIndent("", "  ")
	encoder.Encode(report)
}
```Finally, there's `main.go`, which ties all the components together:```go
// cmd/healthcheck/main.go
package main

import (
	"context"
	"flag"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/david/microplatform/internal/healthcheck"
)

var (
	Version   = "dev"
	BuildTime = "unknown"
)

func main() {
	configPath := flag.String("config", "configs/healthcheck.yaml", "path to configuration file")
	flag.Parse()

	// Initialize structured logger
	logger := slog.New(slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{
		Level: slog.LevelInfo,
	}))
	slog.SetDefault(logger)

	slog.Info("starting health check service",
		"version", Version,
		"build_time", BuildTime,
	)

	// Load configuration
	cfg, err := healthcheck.LoadConfig(*configPath)
	if err != nil {
		slog.Error("failed to load config", "error", err)
		os.Exit(1)
	}

	slog.Info("configuration loaded",
		"targets", len(cfg.Targets),
		"port", cfg.Server.Port,
	)

	// Create checker and reporter
	checker := healthcheck.NewChecker(cfg)
	reporter := healthcheck.NewReporter(checker, cfg)

	// Set up HTTP server for health report API
	mux := http.NewServeMux()
	mux.HandleFunc("/health", func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusOK)
		w.Write([]byte(`{"status":"ok"}`))
	})
	mux.Handle("/report", reporter)
	mux.HandleFunc("/report/", func(w http.ResponseWriter, r *http.Request) {
		// Individual service report
		name := r.URL.Path[len("/report/"):]
		result, ok := checker.GetResult(name)
		if !ok {
			http.Error(w, `{"error":"target not found"}`, http.StatusNotFound)
			return
		}
		w.Header().Set("Content-Type", "application/json")
		fmt.Fprintf(w, `{"name":%q,"status":%q,"latency":%q,"last_check":%q}`,
			result.TargetName, result.Status, result.Latency, result.Timestamp.Format(time.RFC3339))
	})

	server := &http.Server{
		Addr:         fmt.Sprintf(":%d", cfg.Server.Port),
		Handler:      mux,
		ReadTimeout:  cfg.Server.ReadTimeout,
		WriteTimeout: cfg.Server.WriteTimeout,
	}

	// Start components
	checker.Start()
	reporter.Start()

	// Start HTTP server in background
	go func() {
		slog.Info("HTTP server starting", "addr", server.Addr)
		if err := server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			slog.Error("HTTP server error", "error", err)
			os.Exit(1)
		}
	}()

	// Wait for shutdown signal
	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)
	sig := <-sigCh
	slog.Info("received shutdown signal", "signal", sig)

	// Graceful shutdown
	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	reporter.Stop()
	checker.Stop()

	if err := server.Shutdown(ctx); err != nil {
		slog.Error("HTTP server shutdown error", "error", err)
	}

	slog.Info("service stopped gracefully")
}
