### 4. Associate Notes with Users:
Modify your Firestore queries to include the user’s unique ID (`uid`). For example:
```javascript
import { doc, setDoc, collection, query, where, onSnapshot } from "firebase/firestore";
import { auth } from "../firebase.js";

const notesCollection = collection(db, "user_notes");

async function createNote(content) {
  const user = auth.currentUser;
  if (user) {
    const noteRef = doc(notesCollection, `${user.uid}_${Date.now()}`);
    await setDoc(noteRef, { content, uid: user.uid, timestamp: Date.now() });
  } else {
    throw new Error("User not authenticated");
  }
}

function listenForNotes(callback) {
  const user = auth.currentUser;
  if (user) {
    const q = query(notesCollection, where("uid", "==", user.uid));
    onSnapshot(q, (snapshot) => {
      const notes = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      callback(notes);
    });
  }
}
```

### 5. Protect Routes:
Ensure only logged-in users can access certain routes. For example:
```javascript
import { auth } from "../firebase";

router.beforeEach((to, from, next) => {
  const requiresAuth = to.matched.some(record => record.meta.requiresAuth);
  const user = auth.currentUser;

  if (requiresAuth && !user) {
    next("/login");
  } else {
    next();
  }
});
```
Set `meta.requiresAuth: true` for routes requiring authentication.

