package main

import (
    "net/http"
    "github.com/prometheus/client_golang/prometheus"
    "github.com/prometheus/client_golang/prometheus/promhttp"
    "runtime"
)

var (
    requestDuration = prometheus.NewHistogramVec(
        prometheus.HistogramOpts{
            Name:    "custom_request_duration_seconds",
            Help:    "Request duration in seconds.",
            Buckets: prometheus.DefBuckets,
        },
        []string{"handler"},
    )

    errorRate = prometheus.NewCounterVec(
        prometheus.CounterOpts{
            Name: "custom_error_total",
            Help: "Total number of errors.",
        },
        []string{"handler"},
    )

    memoryUsage = prometheus.NewGaugeFunc(
        prometheus.GaugeOpts{
            Name: "custom_memory_usage_bytes",
            Help: "Memory usage in bytes.",
        },
        func() float64 {
            var m runtime.MemStats
            runtime.ReadMemStats(&m)
            return float64(m.Alloc)
        },
    )
)

func init() {
    prometheus.MustRegister(requestDuration)
    prometheus.MustRegister(errorRate)
    prometheus.MustRegister(memoryUsage)
}

func handler(w http.ResponseWriter, r *http.Request) {
    timer := prometheus.NewTimer(requestDuration.WithLabelValues("handler"))
    defer timer.ObserveDuration()

    // Simulate processing
    // If error occurs:
    // errorRate.WithLabelValues("handler").Inc()

    w.Write([]byte("Hello, Prometheus!"))
}

func main() {
    http.HandleFunc("/", handler)
    http.Handle("/metrics", promhttp.Handler())
    http.ListenAndServe(":8080", nil)
}
```

