// internal/metrics/metrics.go
package metrics

import (
	"net/http"
	"runtime"
	"sync"
	"time"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/collectors"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

// Metrics holds all custom Prometheus metrics for a service
type Metrics struct {
	// HTTP request metrics
	RequestDuration *prometheus.HistogramVec
	RequestTotal    *prometheus.CounterVec
	RequestInFlight prometheus.Gauge

	// Error metrics
	ErrorTotal *prometheus.CounterVec
	ErrorRate  *prometheus.GaugeVec

	// Business metrics
	ActiveUsers     prometheus.Gauge
	OrdersProcessed *prometheus.CounterVec
	OrderValue      *prometheus.HistogramVec

	// System metrics
	MemoryUsage     *prometheus.GaugeVec
	GoroutineCount  prometheus.Gauge
	GCDuration      prometheus.Histogram
	OpenConnections *prometheus.GaugeVec

	// Health check metrics
	HealthCheckDuration *prometheus.HistogramVec
	HealthCheckStatus   *prometheus.GaugeVec

	// Database metrics
	DBQueryDuration *prometheus.HistogramVec
	DBQueryTotal    *prometheus.CounterVec
	DBPoolStats     *prometheus.GaugeVec

	registry *prometheus.Registry
	mu       sync.Mutex
}

// NewMetrics creates and registers all metrics
func NewMetrics(serviceName string) *Metrics {
	registry := prometheus.NewRegistry()

	// Register default Go and process collectors
	registry.MustRegister(collectors.NewGoCollector())
	registry.MustRegister(collectors.NewProcessCollector(collectors.ProcessCollectorOpts{}))

	m := &Metrics{
		registry: registry,

		RequestDuration: prometheus.NewHistogramVec(
			prometheus.HistogramOpts{
				Namespace: serviceName,
				Name:      "http_request_duration_seconds",
				Help:      "HTTP request duration in seconds",
				Buckets:   []float64{0.001, 0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5, 10},
			},
			[]string{"method", "path", "status_code"},
		),

		RequestTotal: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Namespace: serviceName,
				Name:      "http_requests_total",
				Help:      "Total number of HTTP requests",
			},
			[]string{"method", "path", "status_code"},
		),

		RequestInFlight: prometheus.NewGauge(
			prometheus.GaugeOpts{
				Namespace: serviceName,
				Name:      "http_requests_in_flight",
				Help:      "Number of HTTP requests currently being processed",
			},
		),

		ErrorTotal: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Namespace: serviceName,
				Name:      "errors_total",
				Help:      "Total number of errors by type",
			},
			[]string{"type", "severity"},
		),

		ErrorRate: prometheus.NewGaugeVec(
			prometheus.GaugeOpts{
				Namespace: serviceName,
				Name:      "error_rate",
				Help:      "Current error rate per second",
			},
			[]string{"type"},
		),

		ActiveUsers: prometheus.NewGauge(
			prometheus.GaugeOpts{
				Namespace: serviceName,
				Name:      "active_users",
				Help:      "Number of currently active users",
			},
		),

		OrdersProcessed: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Namespace: serviceName,
				Name:      "orders_processed_total",
				Help:      "Total number of orders processed",
			},
			[]string{"status"},
		),

		OrderValue: prometheus.NewHistogramVec(
			prometheus.HistogramOpts{
				Namespace: serviceName,
				Name:      "order_value_dollars",
				Help:      "Order value distribution in dollars",
				Buckets:   []float64{10, 25, 50, 100, 250, 500, 1000, 5000},
			},
			[]string{"currency"},
		),

		MemoryUsage: prometheus.NewGaugeVec(
			prometheus.GaugeOpts{
				Namespace: serviceName,
				Name:      "memory_usage_bytes",
				Help:      "Memory usage in bytes by type",
			},
			[]string{"type"},
		),

		GoroutineCount: prometheus.NewGauge(
			prometheus.GaugeOpts{
				Namespace: serviceName,
				Name:      "goroutine_count",
