		),

		DBQueryDuration: prometheus.NewHistogramVec(
			prometheus.HistogramOpts{
				Namespace: serviceName,
				Name:      "db_query_duration_seconds",
				Help:      "Database query duration in seconds",
				Buckets:   []float64{0.001, 0.005, 0.01, 0.05, 0.1, 0.5, 1, 5},
			},
			[]string{"operation", "table"},
		),

		DBQueryTotal: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Namespace: serviceName,
				Name:      "db_queries_total",
				Help:      "Total number of database queries",
			},
			[]string{"operation", "table", "status"},
		),

		DBPoolStats: prometheus.NewGaugeVec(
			prometheus.GaugeOpts{
				Namespace: serviceName,
				Name:      "db_pool_stats",
				Help:      "Database connection pool statistics",
			},
			[]string{"stat"},
		),
	}

	// Register all metrics
	registry.MustRegister(
		m.RequestDuration, m.RequestTotal, m.RequestInFlight,
		m.ErrorTotal, m.ErrorRate,
		m.ActiveUsers, m.OrdersProcessed, m.OrderValue,
		m.MemoryUsage, m.GoroutineCount, m.GCDuration, m.OpenConnections,
		m.HealthCheckDuration, m.HealthCheckStatus,
		m.DBQueryDuration, m.DBQueryTotal, m.DBPoolStats,
	)

	// Start background system metrics collection
	go m.collectSystemMetrics()

	return m
}

// Handler returns an HTTP handler for the /metrics endpoint
func (m *Metrics) Handler() http.Handler {
	return promhttp.HandlerFor(m.registry, promhttp.HandlerOpts{
		EnableOpenMetrics: true,
	})
}

// HTTPMiddleware wraps an HTTP handler with request metrics
func (m *Metrics) HTTPMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		m.RequestInFlight.Inc()
		defer m.RequestInFlight.Dec()

		start := time.Now()
		wrapped := &responseWriter{ResponseWriter: w, statusCode: http.StatusOK}

		next.ServeHTTP(wrapped, r)

		duration := time.Since(start).Seconds()
		statusStr := http.StatusText(wrapped.statusCode)

		m.RequestDuration.WithLabelValues(r.Method, r.URL.Path, statusStr).Observe(duration)
		m.RequestTotal.WithLabelValues(r.Method, r.URL.Path, statusStr).Inc()

		if wrapped.statusCode >= 500 {
			m.ErrorTotal.WithLabelValues("http_5xx", "error").Inc()
		} else if wrapped.statusCode >= 400 {
			m.ErrorTotal.WithLabelValues("http_4xx", "warning").Inc()
		}
	})
}

// collectSystemMetrics periodically collects runtime metrics
func (m *Metrics) collectSystemMetrics() {
	ticker := time.NewTicker(10 * time.Second)
	defer ticker.Stop()

	for range ticker.C {
		var memStats runtime.MemStats
		runtime.ReadMemStats(&memStats)

		m.MemoryUsage.WithLabelValues("alloc").Set(float64(memStats.Alloc))
		m.MemoryUsage.WithLabelValues("total_alloc").Set(float64(memStats.TotalAlloc))
		m.MemoryUsage.WithLabelValues("sys").Set(float64(memStats.Sys))
		m.MemoryUsage.WithLabelValues("heap_alloc").Set(float64(memStats.HeapAlloc))
		m.MemoryUsage.WithLabelValues("heap_inuse").Set(float64(memStats.HeapInuse))
		m.MemoryUsage.WithLabelValues("stack_inuse").Set(float64(memStats.StackInuse))

		m.GoroutineCount.Set(float64(runtime.NumGoroutine()))

		if memStats.NumGC > 0 {
			lastGC := memStats.PauseNs[(memStats.NumGC+255)%256]
			m.GCDuration.Observe(float64(lastGC) / 1e9)
		}
	}
}

// RecordDBQuery records a database query metric
func (m *Metrics) RecordDBQuery(operation, table string, duration time.Duration, err error) {
	status := "success"
	if err != nil {
		status = "error"
		m.ErrorTotal.WithLabelValues("db_error", "error").Inc()
	}
	m.DBQueryDuration.WithLabelValues(operation, table).Observe(duration.Seconds())
	m.DBQueryTotal.WithLabelValues(operation, table, status).Inc()
}

// responseWriter wraps http.ResponseWriter to capture status code
type responseWriter struct {
	http.ResponseWriter
	statusCode int
}

func (rw *responseWriter) WriteHeader(code int) {
	rw.statusCode = code
	rw.ResponseWriter.WriteHeader(code)
}
