// === 修复后 ===
import "regexp"

// 路径归一化：将动态段替换为占位符
var pathNormalizers = []struct {
    pattern *regexp.Regexp
    replace string
}{
    {regexp.MustCompile(`/users/[a-zA-Z0-9-]+`), "/users/:id"},
    {regexp.MustCompile(`/orders/[a-zA-Z0-9-]+`), "/orders/:id"},
    {regexp.MustCompile(`/products/[a-zA-Z0-9-]+`), "/products/:id"},
    {regexp.MustCompile(`/[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}`), "/:uuid"},
    {regexp.MustCompile(`/\d+`), "/:num"},
}

func normalizePath(path string) string {
    normalized := path
    for _, n := range pathNormalizers {
        normalized = n.pattern.ReplaceAllString(normalized, n.replace)
    }
    return normalized
}

func MetricsMiddleware(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        start := time.Now()
        wrapped := &responseWriter{ResponseWriter: w, statusCode: 200}
        next.ServeHTTP(wrapped, r)

        normalizedPath := normalizePath(r.URL.Path)

        httpRequestDuration.WithLabelValues(
            r.Method,
            normalizedPath,  // 归一化后的路径
            fmt.Sprintf("%d", wrapped.statusCode),
        ).Observe(time.Since(start).Seconds())

        httpRequestTotal.WithLabelValues(
            r.Method,
            normalizedPath,
            fmt.Sprintf("%d", wrapped.statusCode),
        ).Inc()
    })
}

type responseWriter struct {
    http.ResponseWriter
    statusCode int
}

func (rw *responseWriter) WriteHeader(code int) {
