```kotlin
import java.security.MessageDigest
import java.security.SecureRandom
import java.util.Base64

object PKCEUtil {

    fun generateCodeVerifier(): String {
        val secureRandom = SecureRandom()
        val codeVerifier = ByteArray(32)
        secureRandom.nextBytes(codeVerifier)
        return Base64.getUrlEncoder().withoutPadding().encodeToString(codeVerifier)
    }

    fun generateCodeChallenge(codeVerifier: String): String {
        return try {
            val bytes = codeVerifier.toByteArray(Charsets.US_ASCII)
            val messageDigest = MessageDigest.getInstance("SHA-256")
            val hashedBytes = messageDigest.digest(bytes)
            Base64.getUrlEncoder().withoutPadding().encodeToString(hashedBytes)
        } catch (e: Exception) {
            throw RuntimeException("Error generating code challenge", e)
        }
    }
}

fun main() {
    val codeVerifier = PKCEUtil.generateCodeVerifier()
    val codeChallenge = PKCEUtil.generateCodeChallenge(codeVerifier)

    println("Code Verifier: $codeVerifier")
    println("Code Challenge: $codeChallenge")
}
```

### What’s Different in Kotlin?
- Kotlin uses top-level functions and objects for utility classes, so this approach avoids the need for a static class.
- Kotlin simplifies working with strings and arrays, making the code cleaner and more concise.

