2. Create a new file `cmd/add.go` for the `add` command:
```go
package cmd

import (
    "fmt"
    "os"
    "gopkg.in/yaml.v3"
    "github.com/spf13/cobra"
)

type Task struct {
    Name      string `yaml:"name"`
    Completed bool   `yaml:"completed"`
}

type Config struct {
    Tasks []Task `yaml:"tasks"`
}

var taskName string

var addCmd = &cobra.Command{
    Use:   "add",
    Short: "Add a new task",
    Run: func(cmd *cobra.Command, args []string) {
        addTask(taskName)
    },
}

func init() {
    addCmd.Flags().StringVarP(&taskName, "name", "n", "", "Name of the task")
    addCmd.MarkFlagRequired("name")
    rootCmd.AddCommand(addCmd)
}

func addTask(name string) {
    // Read the config file
    file, err := os.OpenFile("config.yaml", os.O_RDWR, 0644)
    if err != nil {
        fmt.Println("Error opening config file:", err)
        return
    }
    defer file.Close()

    var config Config
    decoder := yaml.NewDecoder(file)
    if err := decoder.Decode(&config); err != nil {
        fmt.Println("Error decoding YAML:", err)
        return
    }

    // Add the task
    newTask := Task{Name: name, Completed: false}
    config.Tasks = append(config.Tasks, newTask)

    // Write back to the file
    file.Seek(0, 0)
    file.Truncate(0)
    encoder := yaml.NewEncoder(file)
    if err := encoder.Encode(&config); err != nil {
        fmt.Println("Error encoding YAML:", err)
        return
    }
    encoder.Close()

    fmt.Println("Task added successfully!", name)
}
```

This creates an `add` command that allows users to add tasks to the YAML file. You can build additional commands for listing and removing tasks in a similar way. Do you want me to walk you through the `list` or `remove` command next?

